import {
  ChangeDetectionStrategy,
  Component,
  OnInit,
  inject,
  signal,
} from '@angular/core';
import { FormsModule } from '@angular/forms';
import { ApiService, errorMessage } from '../core/api.service';
import { Account, Contact } from '../core/models';

@Component({
  selector: 'app-contacts',
  standalone: true,
  imports: [FormsModule],
  templateUrl: './contacts.component.html',
  styleUrl: '../shared/list.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class ContactsComponent implements OnInit {
  private readonly api = inject(ApiService);

  loading = signal(true);
  error = signal<string | null>(null);
  saving = signal(false);

  accounts = signal<Account[]>([]);
  contacts = signal<Contact[]>([]);

  name = signal('');
  email = signal('');
  phone = signal('');
  accountId = signal('');

  async ngOnInit(): Promise<void> {
    this.loading.set(true);
    try {
      const [contacts, accounts] = await Promise.all([
        this.api.listContacts(),
        this.api.listAccounts(),
      ]);
      this.contacts.set(contacts);
      this.accounts.set(accounts);
      if (accounts[0]) this.accountId.set(accounts[0].id);
    } catch (err) {
      this.error.set(errorMessage(err, 'Could not load contacts.'));
    } finally {
      this.loading.set(false);
    }
  }

  async create(): Promise<void> {
    this.error.set(null);
    if (!this.name().trim() || !this.email().includes('@')) {
      this.error.set('Name and a valid email are required.');
      return;
    }
    if (!this.accountId()) {
      this.error.set('Create an account first, then link the contact to it.');
      return;
    }
    this.saving.set(true);
    try {
      const created = await this.api.createContact({
        name: this.name().trim(),
        email: this.email().trim(),
        phone: this.phone().trim() || undefined,
        accountId: this.accountId(),
      });
      // The create response has no joined account, so label it from the picker.
      const acct = this.accounts().find((a) => a.id === this.accountId());
      const contact = { ...created, accountName: acct?.name ?? created.accountName };
      this.contacts.update((list) => [contact, ...list]);
      this.name.set('');
      this.email.set('');
      this.phone.set('');
    } catch (err) {
      this.error.set(errorMessage(err, 'Could not create the contact.'));
    } finally {
      this.saving.set(false);
    }
  }
}
